 32	  name: string;
 33	  gvk: {
 34	    group: string;
 35	    version: string;
 36	    kind: string;
 37	  };
 38	}
 39	
 40	export const resources: Resource[] = [
 41	  { name: 'AuthPolicies', gvk: resourceGVKMapping['AuthPolicy'] },
 42	  { name: 'DNSPolicies', gvk: resourceGVKMapping['DNSPolicy'] },
 43	  { name: 'RateLimitPolicies', gvk: resourceGVKMapping['RateLimitPolicy'] },
 44	  { name: 'TLSPolicies', gvk: resourceGVKMapping['TLSPolicy'] },
 45	];
 46	
 47	interface ResourceRBAC {
 48	  list: boolean;
 49	  create: boolean;
 50	}
 51	
 52	interface RBACMap {
 53	  [key: string]: ResourceRBAC;
 54	}
 55	
 56	const useResourceRBAC = (resourceKey: string, namespace?: string): ResourceRBAC => {
 57	  const gvk = resourceGVKMapping[resourceKey];
 58	  const resourceName = getResourceNameFromKind(gvk.kind);
 59	  const [listAllowed] = useAccessReview({
 60	    group: gvk.group,
 61	    resource: resourceName,
 62	    verb: 'list',
 63	    namespace,
 64	  });
 65	  const [createAllowed] = useAccessReview({
 66	    group: gvk.group,
 67	    resource: resourceName,
 68	    verb: 'create',
 69	    namespace,
 70	  });
 71	  // console.log(
 72	  //   `[RBAC] ${resourceKey} in ns ${
 73	  //     namespace || 'cluster'
 74	  //   }: list = ${listAllowed}, create = ${createAllowed}`,
 75	  // );
 76	  return { list: listAllowed, create: createAllowed };
 77	};
 78	
 79	export const AllPoliciesListPage: React.FC<{
 80	  activeNamespace: string;
 81	  columns?: TableColumn<K8sResourceCommon>[];
 82	  showAlertGroup?: boolean;
 83	  paginationLimit?: number;
 84	  resourceRBAC: RBACMap;
 85	}> = ({ activeNamespace, columns, showAlertGroup = false, paginationLimit, resourceRBAC }) => {
 86	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
 87	  const [activePerspective] = useActivePerspective();
 88	
 89	  let filteredResources = resources.filter((r) => {
 90	    const allowed = resourceRBAC[r.gvk.kind]?.list;
 91	    return allowed;
 92	  });
 93	
 94	  // Filter out DNSPolicies and TLSPolicies if active perspective is 'dev'
 95	  if (activePerspective === 'dev') {
 96	    filteredResources = filteredResources.filter(
 97	      (resource) => !['DNSPolicies', 'TLSPolicies'].includes(resource.name),
 98	    );
 99	  }
100	
101	  if (filteredResources.length === 0) {
102	    return <NoPermissionsView primaryMessage={t('You do not have permission to view Policies')} />;
103	  }
104	
105	  const [isOpen, setIsOpen] = useState(false);
106	  const history = useHistory();
107	
108	  const onToggleClick = () => setIsOpen(!isOpen);
109	
110	  const onMenuSelect = (_event: React.MouseEvent<Element, MouseEvent>, policyType: string) => {
111	    const resource = resourceGVKMapping[policyType];
112	    const resolvedNamespace = activeNamespace === '#ALL_NS#' ? 'default' : activeNamespace;
113	    const targetUrl = `/k8s/ns/${resolvedNamespace}/${resource.group}~${resource.version}~${resource.kind}/~new`;
114	    history.push(targetUrl);
115	    setIsOpen(false); // Close the dropdown after selecting an option
116	  };
117	
118	  const canCreateAny = ['AuthPolicy', 'RateLimitPolicy', 'DNSPolicy', 'TLSPolicy'].some(
119	    (policy) => resourceRBAC[policy]?.create,
120	  );
121	
122	  const createPolicyItems = ['AuthPolicy', 'RateLimitPolicy']
123	    .concat(activePerspective !== 'dev' ? ['DNSPolicy', 'TLSPolicy'] : [])
124	    .map((policy) => {
125	      return resourceRBAC[policy]?.create ? (
126	        <DropdownItem value={policy} key={policy.toLowerCase()}>
127	          {t(policy)}
128	        </DropdownItem>
129	      ) : (
130	        <Tooltip key={policy} content={t(`You do not have permission to create a ${policy}`)}>
131	          <DropdownItem value={policy} isAriaDisabled>
132	            {t(policy)}
133	          </DropdownItem>
134	        </Tooltip>
135	      );
136	    });
137	
138	  return (
139	    <>
140	      <ListPageBody>
141	        <div className="co-m-nav-title--row kuadrant-resource-create-container">
142	          <ResourceList
143	            resources={filteredResources.map((r) => r.gvk)}
144	            namespace={activeNamespace}
145	            columns={columns}
146	            paginationLimit={paginationLimit}
147	          />
148	
149	          <div className="kuadrant-resource-create-button pf-u-mt-md">
150	            <Dropdown
151	              isOpen={isOpen}
152	              onSelect={onMenuSelect}
153	              onOpenChange={setIsOpen}
154	              toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
155	                <MenuToggle
156	                  ref={toggleRef}
157	                  onClick={onToggleClick}
158	                  isExpanded={isOpen}
159	                  variant={canCreateAny ? 'primary' : 'secondary'}
160	                  isDisabled={!canCreateAny}
161	                >
162	                  {t('Create Policy')}
163	                </MenuToggle>
164	              )}
165	            >
166	              <DropdownList>{createPolicyItems}</DropdownList>
167	            </Dropdown>
168	          </div>
169	        </div>
170	      </ListPageBody>
171	    </>
172	  );
173	};
