175	const PoliciesListPage: React.FC<{
176	  resource: Resource;
177	  activeNamespace: string;
178	  resourceRBAC: RBACMap;
179	}> = ({ resource, activeNamespace, resourceRBAC }) => {
180	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
181	  const resolvedNamespace = activeNamespace === '#ALL_NS#' ? 'default' : activeNamespace;
182	
183	  if (!resourceRBAC[resource.gvk.kind]?.list) {
184	    console.warn(`[PoliciesListPage] No list permission for ${resource.gvk.kind}`);
185	    return (
186	      <NoPermissionsView primaryMessage={t('You do not have permission to view this resource')} />
187	    );
188	  }
189	
190	  return (
191	    <>
192	      <ListPageBody>
193	        <div className="co-m-nav-title--row kuadrant-resource-create-container">
194	          <ResourceList resources={[resource.gvk]} namespace={activeNamespace} />
195	          <div className="kuadrant-resource-create-button pf-u-mt-md">
196	            {resourceRBAC[resource.gvk.kind]?.create ? (
197	              <ListPageCreateLink
198	                to={`/k8s/ns/${resolvedNamespace}/${resource.gvk.group}~${resource.gvk.version}~${resource.gvk.kind}/~new`}
199	              >
200	                {t(`plugin__kuadrant-console-plugin~Create ${resource.gvk.kind}`)}
201	              </ListPageCreateLink>
202	            ) : (
203	              <Tooltip content={t(`You do not have permission to create a ${resource.gvk.kind}`)}>
204	                <span
205	                  className="pf-c-button pf-m-primary pf-u-mt-md pf-u-mr-md"
206	                  aria-disabled="true"
207	                >
208	                  {t(`Create ${resource.gvk.kind}`)}
209	                </span>
210	              </Tooltip>
211	            )}
212	          </div>
213	        </div>
214	      </ListPageBody>
215	    </>
216	  );
217	};
