270	    AuthPolicy: useResourceRBAC('AuthPolicy', nsForCheck),
271	    DNSPolicy: useResourceRBAC('DNSPolicy', nsForCheck),
272	    RateLimitPolicy: useResourceRBAC('RateLimitPolicy', nsForCheck),
273	    TLSPolicy: useResourceRBAC('TLSPolicy', nsForCheck),
274	  };
275	
276	  const permsLoaded = ['AuthPolicy', 'DNSPolicy', 'RateLimitPolicy', 'TLSPolicy'].every(
277	    (key) => resourceRBAC[key] !== undefined,
278	  );
279	  if (!permsLoaded) {
280	    return <div>Loading permissions...</div>;
281	  }
282	
283	  const policyRBACNil =
284	    !resourceRBAC['AuthPolicy'].list &&
285	    !resourceRBAC['RateLimitPolicy'].list &&
286	    !resourceRBAC['DNSPolicy'].list &&
287	    !resourceRBAC['TLSPolicy']?.list;
288	
289	  const All: React.FC = () => (
290	    <AllPoliciesListPage
291	      activeNamespace={activeNamespace}
292	      columns={defaultColumns}
293	      resourceRBAC={resourceRBAC}
294	    />
295	  );
296	
297	  const Auth: React.FC = () => (
298	    <PoliciesListPage
299	      resource={resources[0]}
300	      activeNamespace={activeNamespace}
301	      resourceRBAC={resourceRBAC}
302	    />
303	  );
304	
305	  const RateLimit: React.FC = () => (
306	    <PoliciesListPage
307	      resource={resources[2]}
308	      activeNamespace={activeNamespace}
309	      resourceRBAC={resourceRBAC}
310	    />
311	  );
312	
313	  let pages = [
314	    {
315	      href: '',
316	      name: t('All Policies'),
317	      component: All,
318	    },
319	  ];
320	
321	  if (activePerspective === 'admin') {
322	    const DNS: React.FC = () => (
323	      <PoliciesListPage
324	        resource={resources[1]}
325	        activeNamespace={activeNamespace}
326	        resourceRBAC={resourceRBAC}
327	      />
328	    );
329	    const TLS: React.FC = () => (
330	      <PoliciesListPage
331	        resource={resources[3]}
332	        activeNamespace={activeNamespace}
333	        resourceRBAC={resourceRBAC}
334	      />
335	    );
336	
337	    pages = [
338	      ...pages,
339	      {
340	        href: 'dns',
341	        name: t('DNS'),
342	        component: DNS,
343	      },
344	      {
345	        href: 'tls',
346	        name: t('TLS'),
347	        component: TLS,
348	      },
349	    ];
350	  }
351	
352	  pages = [
353	    ...pages,
354	    {
355	      href: 'auth',
356	      name: t('Auth'),
357	      component: Auth,
358	    },
359	    {
360	      href: 'ratelimit',
361	      name: t('RateLimit'),
362	      component: RateLimit,
363	    },
364	  ];
365	
366	  const handleNamespaceChange = (activeNamespace: string) => {
367	    let currentTab = '';
368	    let activeTab = location.pathname.split('/').pop();
369	    if (activeTab === 'policies') {
370	      activeTab = '';
371	    }
372	
373	    if (activeNamespace !== '#ALL_NS#') {
374	      currentTab = `/kuadrant/ns/${activeNamespace}/policies/${activeTab}`;
375	    } else {
376	      currentTab = `/kuadrant/all-namespaces/policies/${activeTab}`;
377	    }
378	
379	    history.replace(currentTab);
380	  };
381	
382	  return (
383	    <>
384	      <NamespaceBar onNamespaceChange={handleNamespaceChange} />
385	      <Title headingLevel="h1" className="kuadrant-page-title">
386	        {t('Kuadrant')}
387	      </Title>
388	      {policyRBACNil ? (
389	        <NoPermissionsView primaryMessage={t('You do not have permission to view Policies')} />
390	      ) : (
391	        <HorizontalNav pages={pages} />
392	      )}
393	    </>
394	  );
395	};
